Bind a relay command to a ScrollRect's value change using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private ScrollRectCommandBinder _Scroll;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Scroll(Vector2 position) { }
    }


Bind a relay command in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private ScrollRect _scrollRect;
        
        private ScrollRectCommandBinder ScrollCommand => new(_scrollRect);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [RelayCommand]
        private void Scroll(Vector2 position) { }
    }

